.hero h1 {
  font-family: 'Fraunces', serif;
  font-size: clamp(2.4rem, 7vw, 5.5rem);
  font-weight: 900;
  line-height: 1.05;
  letter-spacing: -2px;
  color: var(--ink);
  margin-bottom: 12px;
}

.hero h1 em {
  font-style: italic;
  color: var(--green);
}

.hero .tagline {
  font-size: clamp(0.9rem, 2vw, 1.1rem);
  color: var(--ink-3);
  max-width: 560px;
  margin: 16px auto 0;
  font-weight: 400;
  line-height: 1.65;
}

.hero-platforms {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 10px;
  margin-top: 32px;
}

.platform-pill {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  padding: 8px 18px;
  border-radius: 100px;
  border: 1px solid var(--border-strong);
  background: var(--bg-card);
  font-size: 0.78rem;
  font-weight: 600;
  color: var(--ink-2);
  letter-spacing: 0.3px;
  transition: all 0.2s;
  box-shadow: var(--shadow-sm);
}

.platform-pill:hover {
  border-color: var(--green);
  color: var(--green);
  transform: translateY(-1px);
  box-shadow: var(--shadow-md);
}

.platform-pill .ico { font-size: 1rem; }

/* ════════════════════════════════════════
   NAVBAR
════════════════════════════════════════ */
.nav-wrap {
  position: sticky;
  top: 0;
  z-index: 100;
  background: rgba(244, 237, 228, 0.92);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border-bottom: 1px solid var(--border-strong);
  box-shadow: var(--shadow-sm);
}

.nav-container {
  max-width: 1100px;
  margin: 0 auto;
  padding: 0 clamp(12px, 4vw, 32px);
  display: flex;
  align-items: center;
  height: var(--nav-height);
  gap: 8px;
}

.nav-brand {
  display: flex;
  align-items: center;
  gap: 8px;
  text-decoration: none;
  flex-shrink: 0;
  margin-right: 12px;
}
.nav-brand-icon {
  width: 30px; height: 30px;
  border-radius: 8px;
  background: var(--green);
  display: flex; align-items: center; justify-content: center;
  font-size: 1rem;
  color: #fff;
  flex-shrink: 0;
}
.nav-brand-text {
  font-family: 'Fraunces', serif;
  font-size: 0.95rem;
  font-weight: 700;
  color: var(--ink);
  letter-spacing: -0.3px;
  white-space: nowrap;
}
.nav-brand-year {
  font-family: 'Fira Code', monospace;
  font-size: 0.62rem;
  font-weight: 500;
  color: var(--ink-4);
  letter-spacing: 0.5px;
  margin-left: 2px;
}

.nav-links {
  display: flex;
  align-items: center;
  gap: 2px;
  flex: 1;
  overflow-x: auto;
  scrollbar-width: none;
}
.nav-links::-webkit-scrollbar { display: none; }

.nav-link {
  flex-shrink: 0;
  display: flex;
  align-items: center;
  gap: 5px;
  padding: 10px 12px;
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.5px;
  text-transform: uppercase;
  color: var(--ink-3);
  text-decoration: none;
  transition: color 0.2s;
  border-bottom: 2px solid transparent;
  white-space: nowrap;
  border-radius: 0;
}

.nav-link:hover { color: var(--ink); }
.nav-link.active { color: var(--green); border-bottom-color: var(--green); }

.nav-link .num {
  font-family: 'Fira Code', monospace;
  font-size: 0.6rem;
  color: var(--ink-4);
  transition: color 0.2s;
}
.nav-link.active .num { color: var(--green-light); }

.nav-hamburger {
  display: none;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  gap: 5px;
  width: 38px; height: 38px;
  border: 1px solid var(--border-strong);
  border-radius: var(--radius-xs);
  background: var(--bg-card);
  cursor: pointer;
  flex-shrink: 0;
  margin-left: auto;
  transition: border-color 0.2s;
}
.nav-hamburger:hover { border-color: var(--green); }
.nav-hamburger span {
  display: block;
  width: 18px; height: 2px;
  background: var(--ink-3);
  border-radius: 2px;
  transition: all 0.3s;
  transform-origin: center;
}
.nav-hamburger.open span:nth-child(1) { transform: translateY(7px) rotate(45deg); }
.nav-hamburger.open span:nth-child(2) { opacity: 0; transform: scaleX(0); }
.nav-hamburger.open span:nth-child(3) { transform: translateY(-7px) rotate(-45deg); }

.nav-drawer {
  display: none;
  position: absolute;
  top: 100%;
  left: 0; right: 0;
  background: rgba(244, 237, 228, 0.98);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border-bottom: 1px solid var(--border-strong);
  padding: 8px 0 12px;
  box-shadow: var(--shadow-md);
  z-index: 99;
  animation: slideDown 0.25s ease-out;
}
@keyframes slideDown {
  from { opacity: 0; transform: translateY(-8px); }
  to   { opacity: 1; transform: translateY(0); }

