  display: flex;
  align-items: center;
  gap: 4px;
  padding: 4px 10px;
  border-radius: 5px;
  border: 1px solid rgba(255,255,255,0.1);
  background: transparent;
  color: rgba(255,255,255,0.3);
  font-size: 0.7rem;
  font-family: 'Fira Code', monospace;
  cursor: pointer;
  transition: all 0.2s;
  white-space: nowrap;
  flex-shrink: 0;
}
.copy-btn:hover { border-color: rgba(74,140,65,0.6); color: #7DC96E; }
.copy-btn.ok    { border-color: rgba(74,140,65,0.8); color: #7DC96E; }
.code-body {
  padding: clamp(12px, 3vw, 18px) clamp(14px, 3vw, 22px);
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
}
.code-body pre {
  font-family: 'Fira Code', monospace;
  font-size: clamp(0.7rem, 1.8vw, 0.82rem);
  line-height: 1.75;
  color: #D4C9B8;
  white-space: pre;
  margin: 0;
}
.c  { color: #5A6E44; }
.kw { color: #7DC96E; }
.fl { color: #E8A94B; }
.st { color: #7ABFE8; }
.ou { color: #64748B; font-style: italic; }
.pr { color: #C07AB8; }
.nu { color: #E87070; }

/* ─── Steps ─── */
.steps { margin: 4px 0 24px; }
.step {
  display: flex;
  gap: 16px;
  margin-bottom: 6px;
}
.step-track {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding-top: 2px;
  flex-shrink: 0;
}
.step-dot {
  width: 30px; height: 30px;
  border-radius: 50%;
  border: 2px solid var(--border-strong);
  background: var(--bg-card);
  color: var(--ink-3);
  display: flex; align-items: center; justify-content: center;
  font-family: 'Fira Code', monospace;
  font-size: 0.72rem;
  font-weight: 600;
  flex-shrink: 0;
  transition: all 0.2s;
}
.step-dot.on {
  border-color: var(--green);
  background: var(--green-glow);
  color: var(--green);
}
.step-line {
  width: 2px;
  flex: 1;
  min-height: 20px;
  background: var(--border);
  margin: 5px 0;
}
.step-body { flex: 1; padding-bottom: 12px; min-width: 0; }
.step-h {
  font-weight: 700;
  font-size: 0.95rem;
  color: var(--ink);
  margin-bottom: 5px;
}
.step-p {
  color: var(--ink-3);
  font-size: 0.86rem;
  line-height: 1.6;
}

/* ─── Info Boxes ─── */
.box {
  display: flex;
  gap: 12px;
  padding: 14px 18px;
  border-radius: var(--radius-sm);
  margin: 16px 0;
  font-size: 0.86rem;
  line-height: 1.6;
  color: var(--ink-2);
  align-items: flex-start;
}
.box .ico { flex-shrink: 0; margin-top: 1px; font-size: 1rem; }
.box strong { font-weight: 700; }
.box.tip   { background: var(--green-glow); border: 1px solid rgba(45,90,39,.2); }
.box.warn  { background: var(--amber-glow); border: 1px solid rgba(200,130,10,.2); }
.box.ok    { background: rgba(45,90,39,.06); border: 1px solid rgba(45,90,39,.18); }
.box.info  { background: var(--blue-glow);  border: 1px solid rgba(14,116,144,.2); }
code.ic {
  font-family: 'Fira Code', monospace;
  font-size: 0.8em;
  background: rgba(45,90,39,.1);
  border: 1px solid rgba(45,90,39,.2);
  color: var(--green);
  padding: 1px 6px;
  border-radius: 4px;

