/* ─── Model Cards ─── */
.model-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  overflow: hidden;
  margin-bottom: 22px;
  box-shadow: var(--shadow-sm);
  transition: all 0.25s;
}
.model-card:hover {
  border-color: var(--border-strong);
  box-shadow: var(--shadow-md);
  transform: translateY(-2px);
}
.model-card-top {
  padding: clamp(16px, 3vw, 24px) clamp(16px, 4vw, 28px) 14px;
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 12px;
  border-bottom: 1px solid var(--border);
  flex-wrap: wrap;
}
.model-name {
  font-family: 'Fraunces', serif;
  font-size: clamp(1rem, 3vw, 1.35rem);
  font-weight: 700;
  letter-spacing: -0.5px;
  margin-bottom: 8px;
}
.model-chips { display: flex; gap: 6px; flex-wrap: wrap; }
.chip {
  font-family: 'Fira Code', monospace;
  font-size: 0.68rem;
  font-weight: 500;
  padding: 2px 9px;
  border-radius: 100px;
  background: var(--bg-elevated);
  border: 1px solid var(--border-strong);
  color: var(--ink-3);
}
.model-body {
  padding: clamp(14px, 3vw, 20px) clamp(16px, 4vw, 28px) clamp(16px, 3vw, 24px);
}
.model-desc {
  color: var(--ink-3);
  font-size: 0.88rem;
  margin-bottom: 16px;
  line-height: 1.65;
}

/* ─── Test Questions ─── */
.test-q {
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  border-left: 3px solid;
  border-radius: 0 var(--radius-xs) var(--radius-xs) 0;
  padding: 12px 16px;
  margin-bottom: 10px;
}
.test-q-num {
  font-family: 'Fira Code', monospace;
  font-size: 0.62rem;
  font-weight: 600;
  letter-spacing: 1px;
  text-transform: uppercase;
  margin-bottom: 5px;
}
.test-q-text {
  font-size: 0.86rem;
  color: var(--ink-2);
  line-height: 1.6;
  font-weight: 500;
}

/* ─── Accordion ─── */
.accordion {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  margin-bottom: 10px;
  overflow: hidden;
  box-shadow: var(--shadow-sm);
}
.accordion-trigger {
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 15px 20px;
  background: none;
  border: none;
  color: var(--ink);
  font-family: 'Syne', sans-serif;
  font-size: 0.9rem;
  font-weight: 700;
  cursor: pointer;
  text-align: left;
  gap: 12px;
  transition: background 0.2s;
}
.accordion-trigger:hover { background: var(--bg-elevated); }
.accordion-icon {
  color: var(--ink-4);
  font-size: 0.75rem;
  transition: transform 0.3s;
  flex-shrink: 0;
}
.accordion.open .accordion-icon { transform: rotate(180deg); }
.accordion-body {
  max-height: 0;
  overflow: hidden;
  transition: max-height 0.4s cubic-bezier(0.4,0,0.2,1);
}
.accordion.open .accordion-body { max-height: 6000px; }
.accordion-inner {
  padding: 4px 20px 20px;
  border-top: 1px solid var(--border);
}

/* ─── Back to Top ─── */
.back-top {
  position: fixed;
  bottom: 24px; right: 24px;
  width: 44px; height: 44px;
  border-radius: 12px;
  background: var(--bg-card);
  border: 1px solid var(--border-strong);
  color: var(--ink-3);
  font-size: 1.1rem;
  display: flex; align-items: center; justify-content: center;
  cursor: pointer;
  box-shadow: var(--shadow-md);
  opacity: 0;
  transform: translateY(12px);
  transition: all 0.3s;
  z-index: 90;
}
.back-top.show { opacity: 1; transform: translateY(0); }
.back-top:hover { border-color: var(--green); color: var(--green); }

/* ─── Footer ─── */
footer {
  position: relative;
  z-index: 1;
  text-align: center;
  padding: 40px 20px;
  border-top: 1px solid var(--border-strong);
  color: var(--ink-4);
  font-size: 0.78rem;
  line-height: 1.8;
}
footer a { color: var(--green); text-decoration: none; font-weight: 600; }
footer a:hover { text-decoration: underline; }

.footer-inner {
  max-width: 600px;
  margin: 0 auto;
}

.footer-brand {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 12px;
  font-family: 'Fraunces', serif;
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--ink-2);
}

/* ─── Colour accents per model ─── */
.accent-llama   { color: #2D5A27; }
.accent-deepseek { color: #8B5CF6; }
.accent-gemma   { color: #C8820A; }
.accent-qwen    { color: #B5441E; }
.accent-mistral { color: #0E7490; }

.bl-llama    { border-left-color: #2D5A27; }
.bl-deepseek { border-left-color: #8B5CF6; }
.bl-gemma    { border-left-color: #C8820A; }
.bl-qwen     { border-left-color: #B5441E; }
.bl-mistral  { border-left-color: #0E7490; }

.tq-llama    { color: #2D5A27; }
.tq-deepseek { color: #8B5CF6; }
.tq-gemma    { color: #C8820A; }
.tq-qwen     { color: #B5441E; }
.tq-mistral  { color: #0E7490; }

/* ════════════════════════════════════════
   RESPONSIVE
════════════════════════════════════════ */
@media (max-width: 768px) {
  .nav-links { display: none; }
  .nav-hamburger { display: flex; }
  .nav-brand-year { display: none; }

