  2113→<script>
  2114→// ── Copy button ──
  2115→function doCopy(btn) {
  2116→  const text = btn.closest('.code-block').querySelector('pre').textContent;
  2117→  navigator.clipboard.writeText(text).then(() => {
  2118→    btn.textContent = '✓ Copied';
  2119→    btn.classList.add('ok');
  2120→    setTimeout(() => { btn.textContent = '⎘ Copy'; btn.classList.remove('ok'); }, 2000);
  2121→  });
  2122→}
  2123→
  2124→// ── OS Tabs ──
  2125→document.querySelectorAll('.tab-btn').forEach(btn => {
  2126→  btn.addEventListener('click', () => {
  2127→    const strip = btn.closest('.tab-strip');
  2128→    const group = strip.dataset.group;
  2129→    const os    = btn.dataset.os;
  2130→    strip.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
  2131→    btn.classList.add('active');
  2132→    document.querySelectorAll(`.os-panel[data-group="${group}"]`).forEach(p => p.classList.remove('active'));
  2133→    document.querySelectorAll(`.os-panel[data-group="${group}"][data-os="${os}"]`).forEach(p => p.classList.add('active'));
  2134→  });
  2135→});
  2136→
  2137→// ── Accordion ──
  2138→function toggleAcc(trigger) {
  2139→  trigger.closest('.accordion').classList.toggle('open');
  2140→}
  2141→
  2142→// ── Hamburger / Mobile Nav ──
  2143→const hamburgerBtn = document.getElementById('hamburgerBtn');
  2144→const navDrawer    = document.getElementById('navDrawer');
  2145→
  2146→hamburgerBtn.addEventListener('click', () => {
  2147→  const isOpen = navDrawer.classList.toggle('open');
  2148→  hamburgerBtn.classList.toggle('open', isOpen);
  2149→  hamburgerBtn.setAttribute('aria-expanded', isOpen);
  2150→});
  2151→
  2152→navDrawer.querySelectorAll('.nav-drawer-link').forEach(link => {
  2153→  link.addEventListener('click', () => {
  2154→    navDrawer.classList.remove('open');
  2155→    hamburgerBtn.classList.remove('open');
  2156→    hamburgerBtn.setAttribute('aria-expanded', 'false');
  2157→  });
  2158→});
  2159→
  2160→// ── Scroll: progress bar + back-to-top + active nav ──
  2161→const pgBar   = document.getElementById('pgBar');
  2162→const backTop = document.getElementById('backTop');
  2163→const sections = document.querySelectorAll('.section');
  2164→const navLinks  = document.querySelectorAll('.nav-link');
  2165→const drawerLinks = document.querySelectorAll('.nav-drawer-link');
  2166→
  2167→window.addEventListener('scroll', () => {
  2168→  const scrollY   = window.scrollY;
  2169→  const maxScroll = document.documentElement.scrollHeight - window.innerHeight;
  2170→  pgBar.style.width = (scrollY / maxScroll * 100) + '%';
  2171→  scrollY > 500 ? backTop.classList.add('show') : backTop.classList.remove('show');
  2172→}, { passive: true });
  2173→
  2174→const io = new IntersectionObserver(entries => {
  2175→  entries.forEach(e => {
  2176→    if (e.isIntersecting) {
  2177→      navLinks.forEach(l => l.classList.remove('active'));
  2178→      drawerLinks.forEach(l => l.classList.remove('active'));
  2179→      const id = e.target.id;
  2180→      const activeDesktop = document.querySelector(`.nav-link[href="#${id}"]`);
  2181→      const activeMobile  = document.querySelector(`.nav-drawer-link[href="#${id}"]`);
  2182→      if (activeDesktop) activeDesktop.classList.add('active');
  2183→      if (activeMobile)  activeMobile.classList.add('active');
  2184→    }
  2185→  });
  2186→}, { rootMargin: '-15% 0px -60% 0px' });
  2187→
  2188→sections.forEach(s => io.observe(s));
